export function parseArgs(argv) {
  const result = { _: [] }
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (!arg.startsWith('--')) result._.push(arg)
    else result[arg.slice(2)] = true
  }
  return result
}

import test from 'node:test'
import assert from 'node:assert/strict'
import { parseArgs } from './src/parseArgs.mjs'

test('parseArgs handles booleans, values, equals syntax, and positionals', () => {
  assert.deepEqual(parseArgs(['--verbose', '--count', '3', '--output=dist', 'src/index.js']), {
    _: ['src/index.js'],
    verbose: true,
    count: '3',
    output: 'dist'
  })
})

content.thinking:
Now I understand the issue. The current parser is very simple and doesn't handle all the required cases:

1. It marks ALL `--key` flags as `true`, even when they should have values
2. It doesn't handle `--key=value` syntax properly (the slice gives the full `--key=value` as the key)
3. It doesn't handle `--key value` pairs where the value comes after

Looking at the test case:
- `['--verbose', '--count', '3', '--output=dist', 'src/index.js']`
- Expected: `{ _: ['src/index.js'], verbose: true, count: '3', output: 'dist' }`

So:
- `--verbose` is a boolean flag → `verbose: true`
- `--count 3` is a key-value pair (space separated) → `count: '3'`
- `--output=dist` is an equals syntax → `output: 'dist'`
- `src/index.js` is a positional argument → goes in `_`

I need to fix the parser to:
1. Handle `--key=value` syntax → store key=value pair without the `--`
2. Handle `--key value` pairs → consume next argument as value
3. Handle `--key` booleans → store as `true`
4. Handle positional arguments → collect in `_`

Let me write a corrected version:

```javascript
export function parseArgs(argv) {
  const result = { _: [] }

  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]

    if (!arg.startsWith('--')) {
      result._.push(arg)
      continue
    }

    if (arg.includes('=')) {
      // --key=value syntax
      const key = arg.slice(2, -1)  // Remove -- and =value
      const value = arg.slice(-1)   // Get value after =
      result[key] = value
    } else {
      // --key or --key value
      const key = arg.slice(2)
      if (index + 1 < argv.length && !argv[index + 1].startsWith('--')) {
        // Next arg is a value
        result[key] = argv[index + 1]
        index += 1
      } else {
        // Boolean flag
        result[key] = true
      }
    }
  }

  return result
}
```

I need to reconsider the value extraction. The slice approach for `--output=dist` is incorrect—`slice(-1)` only gets the last character, not the full value. For `--output=dist`, I should capture everything after the equals sign, so `arg.slice(arg.indexOf('=') + 1)` would correctly extract `'dist'`.

